+        "Please call me at (617) 555-0199 or write to 456 Oak Avenue, Boston, MA 02134. " +
+        "My account number is 9876543210 and the SSN is 123-45-6789. " +
+        "For more, visit https://support.example.com/tickets/TKT-48211.";
+
+      function makeChunks(text, chunkSize) {
+        const out = [];
+        for (let i = 0; i < text.length; i += chunkSize) {
